# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_rationaltools.test_log_to_atan","kind":"function","src_hash":"faed89ff4316d9d2","in":{"base":"Any"},"out":{"base":"Any","pred":"log_to_atan(f, g) == fg_ans and log_to_atan(g, f) == -fg_ans"},"spec":{"lhs":"test_log_to_atan()","rhs":"test_log_to_atan produces the expected output","over":{"base":"Any"},"name":"test_log_to_atan_correct"},"guarantee":"test_log_to_atan produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_rationaltools.test_log_to_atan_correct","statement":"Path(test_log_to_atan(x), test_log_to_atan produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8b41997794d83bd9"}
def test_log_to_atan():
    f, g = (Poly(x + S.Half, x, domain='QQ'), Poly(sqrt(3)/2, x, domain='EX'))
    fg_ans = 2*atan(2*sqrt(3)*x/3 + sqrt(3)/3)
    assert log_to_atan(f, g) == fg_ans
    assert log_to_atan(g, f) == -fg_ans


